** Returns the truncated timestamp as a Julian day number.
*/
static void date_truncFunc(
  sqlite3_context *context,
  int argc,
  sqlite3_value **argv
){
  const char *zUnit;
  DateTime x;
  int rc;

  /* Validate argument count */
  if( argc!=2 ){
    sqlite3_result_error(context, "date_trunc() requires exactly 2 arguments", -1);
    return;
  }

  /* Extract and validate unit argument */
  zUnit = (const char*)sqlite3_value_text(argv[0]);
  if( zUnit==0 ){
    sqlite3_result_error(context, "date_trunc() unit must be a string", -1);
    return;
  }

  /* Parse the timestamp */
  rc = isDate(context, 1, &argv[1], &x);
  if( rc ) return;

  /* Get date and time components */
  computeYMD_HMS(&x);

  /* Truncate based on unit */
  if( sqlite3_stricmp(zUnit, "year")==0 ){
    x.M = 1;
    x.D = 1;
    x.h = 0;
    x.m = 0;
    x.s = 0.0;
  }else if( sqlite3_stricmp(zUnit, "month")==0 ){
    x.D = 1;
    x.h = 0;
    x.m = 0;
    x.s = 0.0;
  }else if( sqlite3_stricmp(zUnit, "day")==0 ){
    x.h = 0;
    x.m = 0;
    x.s = 0.0;
  }else if( sqlite3_stricmp(zUnit, "hour")==0 ){
    x.m = 0;
    x.s = 0.0;
  }else if( sqlite3_stricmp(zUnit, "minute")==0 ){
    x.s = (double)((sqlite3_int64)x.s);
  }else if( sqlite3_stricmp(zUnit, "second")==0 ){
    /* Truncate to milliseconds */
    x.s = (double)((sqlite3_int64)(x.s * 1000.0)) / 1000.0;
  }else{
    sqlite3_result_error(context, "date_trunc() invalid unit", -1);
    return;
  }

  /* Clear valid flags and recalculate Julian day */
  x.validJD = 0;
  x.validYMD = 0;
  x.validHMS = 0;
  computeJD(&x);

  /* Return the Julian day number */
  sqlite3_result_double(context, x.iJD / 86400000.0);
